#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int mod=998244353,N=5005;
ll n,w[N],dp[N];
ll qp(ll x,ll y)
{
	y%=(mod-1);
	x%=mod;
	ll ans=1;
	while(y)
	{
		if(y%2==1) ans=(ans*x)%mod;
		x=(x*x)%mod;
		y/=2;
	}
	return ans;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	ll tot=0;
	for(int i=1;i<=n;i++)
	{
		cin>>w[i];
		tot+=w[i];
	}
	dp[0]=1;
	for(int i=2;i<=n;i++)
	{
		for(int j=tot;j>=w[i];j--)
		{
			dp[j]=(dp[j]-dp[j-w[i]]+mod)%mod;
		}
	}
	ll ans=0;
	for(int i=0;i<=tot-w[1];i++)
	{
		if(dp[i]==0) continue;
		ans=(ans+dp[i]*w[1]%mod*qp(w[1]+i,mod-2))%mod;
	}
	cout<<ans;
	return 0;
}
